// 1. Uso Avanzado de Generics con Restricciones e Indexación
interface Identifiable {
  id: string;
}

class DatabaseStore<T extends Identifiable> {
  private registry = new Map<string, T>();

  public save(item: T): void {
    this.registry.set(item.id, item);
  }

  public getById(id: string): T | undefined {
    return this.registry.get(id);
  }

  public getAll(): T[] {
    return Array.from(this.registry.values());
  }
}

// 2. Type Guards Personalizados y Tipos Desconocidos (Unknown)
interface UserPayload {
  username: string;
  email: string;
  role: 'admin' | 'user';
}

// Type guard que valida la estructura exacta en tiempo de ejecución
function isUserPayload(payload: any): payload is UserPayload {
  return (
    payload !== null &&
    typeof payload === 'object' &&
    typeof payload.username === 'string' &&
    typeof payload.email === 'string' &&
    (payload.role === 'admin' || payload.role === 'user')
  );
}

function processIncomingRequest(body: unknown) {
  if (isUserPayload(body)) {
    // Aquí dentro body está tipado al 100% como UserPayload
    console.log(`Procesando usuario: ${body.username} (${body.role})`);
    return body.email;
  } else {
    throw new Error('Payload HTTP inválido. Formato no compatible.');
  }
}

// 3. Decorador de Método Avanzado para Medir Tiempos de Ejecución (Profiling)
function LogExecutionTime() {
  return function (
    target: any,
    propertyKey: string,
    descriptor: PropertyDescriptor
  ) {
    const originalMethod = descriptor.value;

    descriptor.value = async function (...args: any[]) {
      const start = performance.now();
      const result = await originalMethod.apply(this, args);
      const end = performance.now();
      console.log(`[Profiler] ${propertyKey} tardó ${(end - start).toFixed(2)}ms en ejecutarse.`);
      return result;
    };

    return descriptor;
  };
}

class OrderService {
  @LogExecutionTime()
  async processOrder(orderId: string) {
    // Simular retraso de red o procesamiento
    await new Promise(resolve => setTimeout(resolve, 150));
    return { orderId, status: 'processed' };
  }
}

// Ejecución demostrativa simulada
async function run() {
  const store = new DatabaseStore<{ id: string; name: string }>();
  store.save({ id: '001', name: 'Servidor Pro' });
  console.log('Objeto recuperado:', store.getById('001'));

  const service = new OrderService();
  await service.processOrder('ORDER_99');
}

run();

